import React, { memo, useMemo } from 'react';
import styles from './page-bg.module.less';

import bgcb from '@/images/bg-chengbao.png';
import bgcd from '@/images/bg-caidai.png';

import bgFull from '@/images/bg-full.png';
import bgFullAsh from '@/images/bg-full-ash.png';

const Loading = memo(({
  className = '',
  children,
  wrapClassName = '',
  flex,
  ash,
}) => {
  const flexName = useMemo(() => {
    if (!flex) return '';
    if (flex === true) return 'flex';
    return flex;
  }, [flex]);
  return (
    <div className={`flex ${styles['page-bg']} ${ash ? styles['ash'] : ''} ${wrapClassName}`} style={{ backgroundImage: `url(${ash ? bgFullAsh : bgFull})`}}>
      <img src={bgcb} className={styles['chengbao']} />
      <img src={bgcd} className={styles['caidai']} />
      <div className={`${styles['page-bg-inner']} ${flexName} ${className}`}>
        {children}
      </div>
    </div>
  )
});

export default Loading;